            "greeting.new.has_skin": "आह, {skinType} \u2014 {empathy}। मेरे पास आपके लिए कुछ बेहतरीन विकल्प हैं।\n\nक्या आप चाहते हैं कि मैं एक रूटीन सुझाऊं, या क्या आप और भी अधिक सटीक मिलान के लिए हमारी त्वरित प्रश्नोत्तरी में भाग लेना चाहेंगे?",
            "greeting.returning": "वापसी पर स्वागत है! मेरे पास अभी भी आपकी {skinType} प्रोफ़ाइल नोट है। आपकी पिछली यात्रा के बाद से मैं कुछ नई जोड़ियों को देख रहा हूँ और उनके बारे में सुनना चाहता हूँ?",
            "greeting.product_context": "{product} \u2014 अच्छा चयन! आइए जांचें कि क्या यह फॉर्मूला आपकी {skinType} त्वचा के साथ अच्छा काम करता है।\n\nमैं आपको इसके अवयवों के बारे में बता सकता हूं, इसे कैसे लागू करें, या क्या यह आपकी त्वचा के प्रकार के लिए सुरक्षित है। आप क्या जानना चाहेंगे?",
            "greeting.quiz_complete": "बहुत बढ़िया, धन्यवाद! आपके उत्तरों के आधार पर, आपकी त्वचा प्रोफ़ाइल <strong>{skinType}</strong> जैसी दिखती है। मैंने आपके उत्पाद कैटलॉग को व्यक्तिगत मिलान स्कोर के साथ अपडेट कर दिया है।\n\nआगे क्या? मैं एक दिनचर्या सुझा सकता हूं, या आप उत्पाद ब्राउज़ कर सकते हैं और उनमें से किसी के बारे में मुझसे पूछ सकते हैं।",
            "empathy.dry": "वह तंग, प्यासा एहसास इतना असहज हो सकता है, है ना?",
            "empathy.oily": "दोपहर की चमक का संघर्ष वास्तविक है \u2014 मैं समझ गया",
            "empathy.combination": "वह मुश्किल टी-जोन! चमकदार माथा लेकिन सूखे गाल, है ना?",
            "empathy.sensitive": "लालिमा और चुभन कोई मज़ा नहीं है \u2014 आइए अपनी त्वचा के साथ अतिरिक्त कोमलता बरतें",
            "empathy.acne": "ब्रेकआउट्स बहुत जिद्दी और निराशाजनक लग सकते हैं, आइए मिलकर इनसे निपटें",
            "quiz.q1": "आइए सरल शुरुआत करें - दोपहर तक आपकी त्वचा कैसी दिखती है?",
            "quiz.q1.opt1": "जगह-जगह तंग, सूखा या परतदार",
            "quiz.q1.opt2": "सर्वत्र चमकदार और तैलीय",
            "quiz.q1.opt3": "मेरे माथे पर चमक, मेरे गालों पर सूखापन",
            "quiz.q1.opt4": "लाल, खुजलीदार, या आसानी से चुभने वाला",
            "quiz.q2": "समझ गया! और आप कितनी बार ब्रेकआउट्स या बंद रोमछिद्रों से जूझते हैं?",
            "quiz.q2.opt1": "शायद ही कभी या कभी नहीं",
            "quiz.q2.opt2": "बार-बार, मेरे पूरे चेहरे पर",
            "quiz.q2.opt3": "कभी-कभी मुख्य रूप से ठोड़ी या माथा",
            "quiz.q2.opt4": "लाल दाने जिनमें खुजली होती है, वास्तव में ब्लैकहेड्स नहीं",
            "quiz.q3": "लगभग पूरा हो गया! आप अपनी त्वचा के बारे में कौन सी चीज़ सुधारना पसंद करेंगे?",
            "quiz.q3.opt1": "गहरा जलयोजन और मोटापन",
            "quiz.q3.opt2": "तेल को नियंत्रित करना और ब्रेकआउट साफ़ करना",
            "quiz.q3.opt3": "महीन रेखाएं और उम्र बढ़ने के लक्षण मिटते जा रहे हैं",
            "quiz.q3.opt4": "सुखदायक लाली और मेरी बाधा की मरम्मत",
            "quiz.block": "अपना समय लें \u2014 जारी रखने के लिए बस ऊपर दिए गए विकल्पों में से एक पर टैप करें।",
            "quiz.report.title": "आपकी त्वचा विश्लेषण रिपोर्ट",
            "quiz.report.body": "आपके उत्तरों के आधार पर, आपकी प्रोफ़ाइल को इस प्रकार वर्गीकृत किया गया है: <strong>{skinType}</strong>.\n\nआपके उत्पाद कैटलॉग को लाइव आणविक संगतता स्कोर के साथ अद्यतन किया गया है!",
            "quiz.report.rec": "मुझे लगता है कि आप <strong>{product}</strong> ({price}) से शुरुआत करना पसंद करेंगे \u2014 यह आपके लक्ष्यों से खूबसूरती से मेल खाता है।",
            "quiz.suggestion.quiz": "\u2728 प्रश्नोत्तरी लें",
            "quiz.suggestion.routine": "\ud83c\udf1f एक दिनचर्या सुझाएं",
            "quiz.suggestion.product": "\ud83d\uded2 उत्पाद ब्राउज़ करें",
            "suggestion.routine_dry": "शुष्क त्वचा के लिए एक दिनचर्या सुझाएँ",
            "suggestion.routine_oily": "तैलीय त्वचा के लिए एक दिनचर्या सुझाएँ",
            "suggestion.routine_combination": "मिश्रित त्वचा के लिए एक दिनचर्या सुझाएँ",
